// Build the subject DN using a builder so the CN value is treated as opaque data.
// Concatenating the subject into "CN=" + subject makes the X.500 parser interpret
// DN-special characters (e.g. '=', ',', '+', '/') as DN syntax, which fails for
// client IDs / entity IDs shaped like URLs (see keycloak#50177).
X500Name subjectDN = new X500NameBuilder(BCStyle.INSTANCE).addRDN(BCStyle.CN, subject).build();
Date validityStartDate = new Date(System.currentTimeMillis() - 100000);

