// Build the subject DN treating the supplied value as an opaque CN attribute value.
// Parsing "CN=" + subject via the X500Principal(String) RFC 2253 parser fails when the
// value contains DN-special characters (e.g. '=', ',', '+', '/') as found in client IDs /
// entity IDs shaped like URLs (see keycloak#50177). Using the builder encodes the value
// safely without treating those characters as DN syntax.
private static X500Principal subjectToX500Principle(String subject) {
    return new X500PrincipalBuilder()
            .addItem(X500AttributeTypeAndValue.createUtf8(X500.OID_AT_COMMON_NAME, subject))
            .build();
}

