package org.keycloak.crypto.def.test;

import java.security.KeyPair;
import java.security.cert.X509Certificate;

import javax.naming.ldap.LdapName;
import javax.naming.ldap.Rdn;

import org.junit.Assert;
import org.junit.ClassRule;
import org.junit.Test;
import org.keycloak.common.util.CertificateUtils;
import org.keycloak.common.util.KeyUtils;
import org.keycloak.rule.CryptoInitRule;

/**
 * Verifies that self-signed certificates can be generated for subjects (client IDs / SAML entity IDs)
 * that contain URL query-string or X.500 DN-special characters.
 *
 * Regression test for keycloak#50177 where a SAML Client ID such as
 * {@code https://example.com/?action=sso_id} caused certificate generation to fail because the
 * subject was concatenated directly into an X.500 name string.
 */
public class DefaultCryptoCertificateSubjectTest {

    @ClassRule
    public static CryptoInitRule cryptoInitRule = new CryptoInitRule();

    private static final String[] SUBJECTS = {
            "https://example.com/?action=sso_id",
            "https://example.com/app?a=1&b=2",
            "client=with=equals",
            "path/with/slashes",
            "scheme:with:colons",
            "a,b+c",
            "plain-client-id"
    };

    @Test
    public void generateCertificateForSubjectsWithSpecialCharacters() throws Exception {
        KeyPair keyPair = KeyUtils.generateRsaKeyPair(2048);

        for (String subject : SUBJECTS) {
            X509Certificate certificate = CertificateUtils.generateV1SelfSignedCertificate(keyPair, subject);
            Assert.assertNotNull("Certificate should be generated for subject: " + subject, certificate);

            String cn = extractCommonName(certificate.getSubjectX500Principal().getName());
            Assert.assertEquals("CN should round-trip the original subject value", subject, cn);
        }
    }

    private static String extractCommonName(String dn) throws Exception {
        LdapName ldapName = new LdapName(dn);
        for (Rdn rdn : ldapName.getRdns()) {
            if ("CN".equalsIgnoreCase(rdn.getType())) {
                return rdn.getValue().toString();
            }
        }
        throw new AssertionError("No CN found in DN: " + dn);
    }
}

